bash_commands.command:
cp /workspace/pkg/apis/core/types.go /tmp/types_backup.go && cat /workspace/pkg/apis/core/types.go | sed '/TaintEffectPreferNoSchedule TaintEffect = "PreferNoSchedule"/a\	// Do not allow new pods to schedule onto the node unless they tolerate the taint,
	// and additionally remove the node from any Service EndpointSlices.
	// Existing pods are not evicted.
	// Enforced by the scheduler and the endpoint slice controller.
	TaintEffectNoScheduleNoTraffic TaintEffect = "NoScheduleNoTraffic"
' > /tmp/types_new.go && cp /tmp/types_new.go /workspace/pkg/apis/core/types.go && echo "Modified successfully"

cat /workspace/pkg/apis/core/types.go | sed 's/TaintEffectPreferNoSchedule TaintEffect = "PreferNoSchedule"/TaintEffectPreferNoSchedule TaintEffect = "PreferNoSchedule"
	// Do not allow new pods to schedule onto the node unless they tolerate the taint,
	// and additionally remove the node from any Service EndpointSlices.
	// Existing pods are not evicted.
	// Enforced by the scheduler and the endpoint slice controller.
	TaintEffectNoScheduleNoTraffic TaintEffect = "NoScheduleNoTraffic"/' > /tmp/types_modified.go && wc -l /tmp/types_modified.go

sed -i.bak '3176 a\t// Do not allow new pods to schedule onto the node unless they tolerate the taint,
	// and additionally remove the node from any Service EndpointSlices.
	// Existing pods are not evicted.
	// Enforced by the scheduler and the endpoint slice controller.
	TaintEffectNoScheduleNoTraffic TaintEffect = "NoScheduleNoTraffic"' /workspace/pkg/apis/core/types.go 2>&1 && echo "Successfully modified" || echo "Modification failed: $?"

git show HEAD:pkg/apis/core/types.go | sed '/TaintEffectPreferNoSchedule TaintEffect = "PreferNoSchedule"/a\t// Do not allow new pods to schedule onto the node unless they tolerate the taint,
	// and additionally remove the node from any Service EndpointSlices.
	// Existing pods are not evicted.
	// Enforced by the scheduler and the endpoint slice controller.
	TaintEffectNoScheduleNoTraffic TaintEffect = "NoScheduleNoTraffic"' > /tmp/types_final.go && wc -l /tmp/types_final.go

cat > /tmp/types_patch.diff << 'PATCHEOF'
--- a/pkg/apis/core/types.go
+++ b/pkg/apis/core/types.go
@@ -3173,6 +3173,10 @@ const (
 	// Like TaintEffectNoSchedule, but the scheduler tries not to schedule
 	// new pods onto the node, rather than prohibiting new pods from scheduling
 	// onto the node entirely. Enforced by the scheduler.
 	TaintEffectPreferNoSchedule TaintEffect = "PreferNoSchedule"
+	// Do not allow new pods to schedule onto the node unless they tolerate the taint,
+	// and additionally remove the node from any Service EndpointSlices.
+	// Existing pods are not evicted. Enforced by the scheduler.
+	TaintEffectNoScheduleNoTraffic TaintEffect = "NoScheduleNoTraffic"

 	// Evict any already-running pods that do not tolerate the taint.
 	// Currently enforced by NodeController.
PATCHEOF
patch -p1 < /tmp/types_patch.diff --dry-run 2>&1 | head -20

code_changes.new_string:
// These are valid values for TaintEffect
const (
	// Do not allow new pods to schedule onto the node unless they tolerate the taint,
	// but allow all pods submitted to Kubelet without going through the scheduler
	// to start, and allow all already-running pods to continue running.
	// Enforced by the scheduler.
	TaintEffectNoSchedule TaintEffect = "NoSchedule"
	// Like TaintEffectNoSchedule, but the scheduler tries not to schedule
	// new pods onto the node, rather than prohibiting new pods from scheduling
	// onto the node entirely. Enforced by the scheduler.
	TaintEffectPreferNoSchedule TaintEffect = "PreferNoSchedule"
	// Do not allow new pods to schedule onto the node unless they tolerate the taint,
	// and additionally remove the node from any Service EndpointSlices.
	// Existing pods are not evicted.
	// Enforced by the scheduler and the endpoint slice controller.
	TaintEffectNoScheduleNoTraffic TaintEffect = "NoScheduleNoTraffic"

	// Evict any already-running pods that do not tolerate the taint.
	// Currently enforced by NodeController.
	TaintEffectNoExecute TaintEffect = "NoExecute"
)

